\displaystyle{\begin{aligned}
  \frac{{\frac{1}{k-5}+\frac{3}{k+5}}}{{1-\frac{1}{k+5}}} \amp = \frac{({\frac{1}{k-5}+\frac{3}{k+5}})\cdot{\left(k-5\right)\mathopen{}\left(k+5\right)}}{({1-\frac{1}{k+5}})\cdot{\left(k-5\right)\mathopen{}\left(k+5\right)}} \\
    \amp = \frac{{\frac{1}{k-5}\mathopen{}\left(k-5\right)\mathopen{}\left(k+5\right)+\frac{3}{k+5}\mathopen{}\left(k-5\right)\mathopen{}\left(k+5\right)}}{{\left(k-5\right)\mathopen{}\left(k+5\right)-\frac{1}{k+5}\mathopen{}\left(k-5\right)\mathopen{}\left(k+5\right)}} \\
    \amp = \frac{{k+5+3\mathopen{}\left(k-5\right)}}{{k^{2}-25-\left(k-5\right)}}, k \ne -5 \text{ and }  k \ne 5 \\
    \amp = \frac{{k+5+3k-15}}{{k^{2}-25-k+5}}, k \ne -5 \text{ and }  k \ne 5 \\
    \amp = \frac{{4k-10}}{{k^{2}-k-20}}, k \ne -5 \text{ and }  k \ne 5 \\
    \amp = {\frac{2\mathopen{}\left(2k-5\right)}{\left(k+4\right)\mathopen{}\left(k-5\right)}, k\ne -5}
\end{aligned}
    }
